#include <stdio.h>
#include <stdlib.h>

int main() {
    float prixUnitaire, quantite, totalHT, remise, totalApresRemise, tva, totalTTC;

    // Saisie des données
    printf("Entrez le prix unitaire de l'article (FCFA) : ");
    scanf("%f", &prixUnitaire);

    printf("Entrez la quantite achetee : ");
    scanf("%f", &quantite);

    // Calcul du total HT
    totalHT = prixUnitaire * quantite;

    // Application de la remise si nécessaire
    if (totalHT > 100000) {
        remise = totalHT * 0.05;
        totalApresRemise = totalHT - remise;
        printf("Remise de 5%% accordee (%.2f FCFA)\n", remise);
    } else {
        remise = 0;
        totalApresRemise = totalHT;
        printf("Aucune remise accordee\n");
    }

    // Calcul de la TVA (19.25%)
    tva = totalApresRemise * 0.1925;
    totalTTC = totalApresRemise + tva;

    // Affichage des résultats
    printf("\n--- FACTURE ---\n");
    printf("Total HT        : %.2f FCFA\n", totalHT);
    printf("Remise          : %.2f FCFA\n", remise);
    printf("Total apres remise : %.2f FCFA\n", totalApresRemise);
    printf("TVA (19.25%%)    : %.2f FCFA\n", tva);
    printf("Total TTC       : %.2f FCFA\n", totalTTC);

    return 0;
}
```
